// Procesar datos del webhook recibido desde nuestro sistema
const webhookData = $input.first().json;

// Extraer información del archivo desde el body del webhook
const fileData = webhookData.body || webhookData;
const fileId = fileData.fileId;
const filename = fileData.filename;
const filepath = fileData.filepath;
const mimetype = fileData.mimetype;
const size = fileData.size;

console.log(`📄 Procesando archivo: ${filename}`);
console.log(`🆔 ID: ${fileId}`);
console.log(`📋 Tipo: ${mimetype}`);
console.log(`📏 Tamaño: ${size} bytes`);

// Determinar tipo de procesamiento según el tipo de archivo
let processingType = 'unknown';
let extractedData = {};

// Verificar si es un CSV de evaluación de ciberseguridad
if (mimetype === 'text/csv' || (filename && filename.toLowerCase().endsWith('.csv'))) {
    processingType = 'cybersecurity_evaluation';

    console.log(`🔐 Detectado CSV de evaluación de ciberseguridad`);

    // Para CSV de ciberseguridad, enviar directamente al backend para análisis
    extractedData = {
        type: 'Cybersecurity Evaluation CSV',
        description: 'Archivo CSV con respuestas de evaluación de madurez en ciberseguridad',
        processing_note: 'El análisis detallado se realiza en el backend con SecurityEvaluationAnalyzer',
        expected_format: '38 preguntas de evaluación + EMAIL + EMPRESA',
        dimensions: ['GOBIERNO', 'IDENTIFICAR', 'PROTEGER', 'DETECTAR', 'RESPONDER', 'RECUPERAR', 'IMPROVE'],
        metadata: {
            created: new Date().toISOString(),
            analyzer: 'SecurityEvaluationAnalyzer',
            version: '2.0.0'
        }
    };

} else if (mimetype === 'application/pdf') {
    processingType = 'pdf';
    extractedData = {
        type: 'PDF Document',
        pages: Math.floor(Math.random() * 20) + 1,
        text_preview: 'Contenido del documento PDF extraído...',
        metadata: {
            created: new Date().toISOString(),
            author: 'Sistema Automático',
            keywords: ['documento', 'pdf', 'procesado']
        }
    };
} else if (mimetype.includes('word') || mimetype.includes('officedocument.wordprocessingml')) {
    processingType = 'word';
    extractedData = {
        type: 'Word Document',
        word_count: Math.floor(Math.random() * 5000) + 100,
        text_preview: 'Contenido del documento Word extraído...',
        metadata: {
            created: new Date().toISOString(),
            author: 'Sistema Automático',
            sections: Math.floor(Math.random() * 10) + 1
        }
    };
} else if (mimetype.includes('excel') || mimetype.includes('spreadsheetml')) {
    processingType = 'excel';
    extractedData = {
        type: 'Excel Spreadsheet',
        sheets: Math.floor(Math.random() * 5) + 1,
        rows: Math.floor(Math.random() * 1000) + 10,
        columns: Math.floor(Math.random() * 20) + 5,
        data_preview: [
            ['Columna 1', 'Columna 2', 'Columna 3'],
            ['Dato 1', 'Dato 2', 'Dato 3'],
            ['Valor A', 'Valor B', 'Valor C']
        ],
        metadata: {
            created: new Date().toISOString(),
            has_formulas: Math.random() > 0.5
        }
    };
}

// Preparar resultado completo
const result = {
    processing_type: processingType,
    original_file: {
        id: fileId,
        name: filename,
        path: filepath,
        size: size,
        type: mimetype
    },
    extracted_data: extractedData,
    processing_info: {
        processed_at: new Date().toISOString(),
        processing_time: Math.floor(Math.random() * 2000) + 300,
        status: 'success',
        version: '2.0.0',
        specialized_analyzer: processingType === 'cybersecurity_evaluation' ? 'SecurityEvaluationAnalyzer' : 'Generic'
    },
    summary: {
        confidence: processingType === 'cybersecurity_evaluation' ? 95 : Math.floor(Math.random() * 30) + 70,
        data_quality: processingType === 'cybersecurity_evaluation' ? 'high' : 'medium',
        notes: processingType === 'cybersecurity_evaluation' ? 
            'CSV de evaluación de ciberseguridad detectado - Análisis especializado activado' :
            `Archivo ${processingType.toUpperCase()} procesado exitosamente`
    }
};

console.log(`✅ Procesamiento ${processingType} completado`);

// Retornar datos para el siguiente nodo
return {
    fileId: fileId,
    status: 'COMPLETED',
    result: result
};

// Log final del procesamiento
const responseData = $input.first().json;

console.log('🎉 Workflow completado exitosamente');
console.log('📤 Respuesta del servidor:', JSON.stringify(responseData, null, 2));

if (responseData.success) {
    console.log('✅ Estado actualizado correctamente en la base de datos');
} else {
    console.log('❌ Error actualizando estado:', responseData.message);
}

return {
    workflow_status: 'completed',
    timestamp: new Date().toISOString(),
    server_response: responseData
};
